import React, { useState, useEffect, useRef } from 'react';

// Movie images - matched to existing data
const movieImageMap = {
  'Inception': '/images/inception.jpg',
  'The Dark Knight': '/images/dark-knight.jpg',
  'Interstellar': '/images/interstellar.jpg',
  'Titanic': '/images/titanic.jpg',
  'The Room': '/images/the-room.jpg',
};

const getFallbackImage = () => {
  return 'https://images.unsplash.com/photo-1485846234645-a62644f84728?q=80&w=2059&auto=format&fit=crop';
};

const getMovieImage = (title, poster = null) => {
  if (poster) {
    // If it's just a filename from the backend initial data, prepend /images/
    if (!poster.startsWith('http') && !poster.startsWith('/') && !poster.startsWith('blob:')) {
      return `/images/${poster}`;
    }
    return poster;
  }
  return movieImageMap[title] || getFallbackImage();
};

const MovieManager = () => {
  const [movies, setMovies] = useState([]);
  const [loading, setLoading] = useState(false);
  const [showForm, setShowForm] = useState(false);
  const [editingId, setEditingId] = useState(null);
  const [filterRating, setFilterRating] = useState('');
  const [searchTerm, setSearchTerm] = useState('');
  // Upload state
  const [uploading, setUploading] = useState(false);
  const [uploadProgress, setUploadProgress] = useState(0);
  const [previewImage, setPreviewImage] = useState(null);
  const [uploadedPoster, setUploadedPoster] = useState('');
  const fileInputRef = useRef(null);

  const [formData, setFormData] = useState({
    title: '',
    genre: '',
    rating: '',
    recommendation: 'Yes'
  });

  useEffect(() => {
    fetchMovies();
  }, [filterRating]);

  const fetchMovies = async () => {
    setLoading(true);
    try {
      const url = filterRating ? `http://localhost:5000/movies?rating=${filterRating}` : 'http://localhost:5000/movies';
      const response = await fetch(url);
      const data = await response.json();
      setMovies(data);
    } catch (error) {
      console.error('Error fetching movies:', error);
      alert('Failed to fetch movies');
    }
    setLoading(false);
  };

  const handleImageUpload = async (e) => {
    const file = e.target.files[0];
    if (!file) return;

    // Preview
    const reader = new FileReader();
    reader.onloadend = () => {
      setPreviewImage(reader.result);
    };
    reader.readAsDataURL(file);

    setUploading(true);
    const formDataUpload = new FormData();
    formDataUpload.append('poster', file);

    try {
      const response = await fetch('http://localhost:5000/movies/upload', {
        method: 'POST',
        body: formDataUpload,
      });

      const result = await response.json();
      if (response.ok) {
        setUploadedPoster(result.path);
        setUploadProgress(100);
        alert('✅ Image uploaded successfully!');
      } else {
        alert(result.error || 'Upload failed');
      }
    } catch (error) {
      alert('Upload failed: ' + error.message);
    }
    setUploading(false);
    setUploadProgress(0);
  };

  const handleSubmit = async (e) => {
    e.preventDefault();
    if (!formData.title || !formData.genre || !formData.rating) {
      alert('Title, genre, and rating are required');
      return;
    }

    try {
      const submitData = {
        title: formData.title,
        genre: formData.genre,
        rating: parseInt(formData.rating),
        recommendation: formData.recommendation,
        poster: uploadedPoster || null
      };

      if (editingId) {
        const response = await fetch(`http://localhost:5000/movies/${editingId}`, {
          method: 'PATCH',
          headers: { 'Content-Type': 'application/json' },
          body: JSON.stringify(submitData)
        });
        const updated = await response.json();
        setMovies(movies.map(m => m.id === editingId ? updated : m));
      } else {
        const response = await fetch('http://localhost:5000/movies', {
          method: 'POST',
          headers: { 'Content-Type': 'application/json' },
          body: JSON.stringify(submitData)
        });
        const newMovie = await response.json();
        setMovies([...movies, newMovie]);
      }
      resetForm();
      fetchMovies();
    } catch (error) {
      console.error('Error saving movie:', error);
      alert('Failed to save movie');
    }
  };

  const resetForm = () => {
    setShowForm(false);
    setEditingId(null);
    setFormData({ title: '', genre: '', rating: '', recommendation: 'Yes' });
    setPreviewImage(null);
    setUploadedPoster('');
    if (fileInputRef.current) fileInputRef.current.value = '';
  };

  const handleEdit = (movie) => {
    setFormData(movie);
    setUploadedPoster(movie.poster || '');
    setEditingId(movie.id);
    setShowForm(true);
  };

  const handleDelete = async (id) => {
    if (!window.confirm('Are you sure you want to delete this movie?')) return;
    try {
      await fetch(`http://localhost:5000/movies/${id}`, { method: 'DELETE' });
      setMovies(movies.filter(m => m.id !== id));
    } catch (error) {
      alert('Failed to delete movie');
    }
  };

  const filteredMovies = movies.filter(movie => 
    movie.title.toLowerCase().includes(searchTerm.toLowerCase()) ||
    movie.genre.toLowerCase().includes(searchTerm.toLowerCase())
  );

  const genreColors = {
    'Sci-Fi': 'from-blue-600 to-cyan-600',
    'Action': 'from-red-600 to-orange-600',
    'Drama': 'from-purple-600 to-pink-600',
    'Comedy': 'from-yellow-600 to-orange-600',
    'Horror': 'from-gray-800 to-red-900',
    'Romance': 'from-pink-600 to-rose-600',
  };

  const getRatingColor = (rating) => {
    if (rating >= 4) return 'text-green-400 bg-green-500/20';
    if (rating >= 3) return 'text-yellow-400 bg-yellow-500/20';
    return 'text-red-400 bg-red-500/20';
  };

  return (
    <div className="w-full space-y-12">
      {/* Top Section */}
      <div className="relative mb-20">
        {/* Background glow Decor */}
        <div className="absolute -top-40 -left-40 w-80 h-80 bg-yellow-500/10 rounded-full blur-[120px] pointer-events-none" />
        <div className="absolute -top-20 -right-20 w-60 h-60 bg-orange-600/10 rounded-full blur-[100px] pointer-events-none" />

        <div className="flex flex-col lg:flex-row items-start lg:items-center justify-between gap-8 mb-12">
          <div className="space-y-4">
            <div className="inline-flex items-center gap-2 px-4 py-1.5 rounded-full bg-yellow-500/10 border border-yellow-500/20 text-yellow-500 text-xs font-bold uppercase tracking-widest">
              ✨ Discover Excellence
            </div>
            <h2 className="text-5xl md:text-7xl font-black text-white tracking-tight leading-tight">
              Featured <span className="text-transparent bg-clip-text bg-gradient-to-r from-yellow-400 via-orange-400 to-yellow-600">Cinema</span>
            </h2>
            <p className="text-xl text-slate-400 max-w-2xl font-medium leading-relaxed">
              Explore our curated selection of cinematic masterpieces. Rate, review, and organize your personal watch history.
            </p>
          </div>
          <button
            onClick={() => setShowForm(true)}
            className="group relative bg-white text-slate-900 font-black py-5 px-10 rounded-2xl transition-all duration-300 hover:scale-105 active:scale-95 shadow-[0_0_40px_rgba(255,255,255,0.1)] overflow-hidden"
          >
            <div className="absolute inset-0 bg-gradient-to-r from-yellow-400 to-orange-500 opacity-0 group-hover:opacity-100 transition-opacity duration-300" />
            <span className="relative z-10 flex items-center gap-3 decoration-none group-hover:text-white transition-colors">
              <span className="text-2xl">➕</span>
              <span className="text-lg">Add to Collection</span>
            </span>
          </button>
        </div>

        {/* Search & Filter */}
        <div className="flex flex-col md:flex-row gap-4 p-2 bg-slate-800/40 backdrop-blur-3xl rounded-[2rem] border border-white/5 shadow-2xl overflow-hidden group">
          <div className="flex-1 relative flex items-center">
            <span className="absolute left-6 text-slate-500 group-focus-within:text-yellow-400 transition-colors">🔍</span>
            <input
              type="text"
              placeholder="Search by title, genre, or director..."
              value={searchTerm}
              onChange={(e) => setSearchTerm(e.target.value)}
              className="w-full bg-transparent border-none rounded-2xl pl-16 pr-6 py-5 text-white placeholder-slate-500 focus:ring-0 text-lg font-medium"
            />
          </div>
          <div className="h-10 w-px bg-white/10 hidden md:block self-center" />
          <select
            value={filterRating}
            onChange={(e) => setFilterRating(e.target.value)}
            className="bg-transparent border-none rounded-2xl px-8 py-5 text-white font-bold focus:ring-0 appearance-none cursor-pointer hover:text-yellow-400 transition-colors"
          >
            <option value="" className="bg-slate-900">All Masterpieces</option>
            <option value="5" className="bg-slate-900">⭐⭐⭐⭐⭐ Five Stars</option>
            <option value="4" className="bg-slate-900">⭐⭐⭐⭐ Excellent</option>
            <option value="3" className="bg-slate-900">⭐⭐⭐ Decent</option>
            <option value="2" className="bg-slate-900">⭐⭐ Below Average</option>
            <option value="1" className="bg-slate-900">⭐ Poor</option>
          </select>
        </div>
      </div>

      {/* Add/Edit Form */}
      {showForm && (
        <div className="max-w-4xl mx-auto bg-gradient-to-br from-slate-800/90 to-slate-900/90 backdrop-blur-xl rounded-3xl p-10 border border-yellow-500/20 shadow-2xl">
          <div className="flex items-center justify-between mb-10">
            <h3 className="text-3xl font-bold text-white">
              {editingId ? '✏️ Edit Movie' : '🎬 Add New Movie'}
            </h3>
            <button
              onClick={resetForm}
              className="px-8 py-3 bg-slate-700 hover:bg-slate-600 text-white font-bold rounded-xl transition-all duration-300"
            >
              Cancel
            </button>
          </div>

          <form onSubmit={handleSubmit} className="grid grid-cols-1 lg:grid-cols-2 gap-8">
            {/* Poster Upload */}
            <div>
              <label className="block text-slate-300 font-bold mb-4 text-xl">🖼️ Movie Poster</label>
              <div className="space-y-4">
                <input
                  ref={fileInputRef}
                  type="file"
                  accept="image/jpeg,image/png,image/jpg"
                  onChange={handleImageUpload}
                  className="w-full h-48 border-2 border-dashed border-slate-600 rounded-2xl p-12 text-center text-lg cursor-pointer hover:border-yellow-400/70 bg-slate-900/50 hover:bg-slate-800/50 transition-all file:mr-4 file:py-4 file:px-6 file:rounded-xl file:border-0 file:text-sm file:font-semibold file:bg-gradient-to-r file:from-yellow-500 file:to-orange-500 file:text-white hover:file:bg-gradient-to-r hover:file:from-yellow-600 hover:file:to-orange-600"
                />
                {uploading && (
                  <div className="w-full bg-slate-800 rounded-full h-4 overflow-hidden">
                    <div 
                      className="bg-gradient-to-r from-emerald-500 to-teal-500 h-full transition-all duration-1000"
                      style={{ width: `${uploadProgress}%` }}
                    />
                  </div>
                )}
                {uploadedPoster && (
                  <div className="p-4 bg-emerald-500/10 border border-emerald-500/30 rounded-2xl text-emerald-400 font-mono text-sm">
                    ✅ Uploaded: {uploadedPoster.split('/').pop()}
                  </div>
                )}
              </div>
            </div>

            {/* Preview */}
            {previewImage && (
              <div className="relative group">
                <img 
                  src={previewImage} 
                  alt="Preview" 
                  className="w-full h-96 object-cover rounded-3xl shadow-2xl ring-4 ring-slate-700/50 group-hover:ring-yellow-400/30 transition-all"
                />
                <div className="absolute inset-0 bg-gradient-to-t from-black/50 to-transparent rounded-3xl opacity-0 group-hover:opacity-100 transition-opacity" />
                <div className="absolute top-4 right-4 bg-emerald-500/90 text-white px-4 py-2 rounded-2xl font-bold text-sm shadow-lg backdrop-blur-sm">
                  Preview ✓
                </div>
              </div>
            )}

            {/* Form Fields */}
            <div>
              <label className="block text-slate-300 font-bold mb-3 text-lg">🎥 Movie Title</label>
              <input
                type="text"
                placeholder="e.g. Inception"
                value={formData.title}
                onChange={(e) => setFormData({ ...formData, title: e.target.value })}
                className="w-full bg-slate-800/50 border border-slate-600/50 rounded-2xl px-6 py-5 text-white placeholder-slate-400 focus:outline-none focus:border-yellow-400/60 focus:ring-4 focus:ring-yellow-400/20 transition-all text-xl font-semibold"
                required
              />
            </div>
            <div>
              <label className="block text-slate-300 font-bold mb-3 text-lg">🎭 Genre</label>
              <input
                type="text"
                placeholder="Sci-Fi, Action, Drama..."
                value={formData.genre}
                onChange={(e) => setFormData({ ...formData, genre: e.target.value })}
                className="w-full bg-slate-800/50 border border-slate-600/50 rounded-2xl px-6 py-5 text-white placeholder-slate-400 focus:outline-none focus:border-yellow-400/60 focus:ring-4 focus:ring-yellow-400/20 transition-all"
                required
              />
            </div>
            <div>
              <label className="block text-slate-300 font-bold mb-3 text-lg">⭐ Rating (1-5)</label>
              <input
                type="number"
                min="1"
                max="5"
                value={formData.rating}
                onChange={(e) => setFormData({ ...formData, rating: e.target.value })}
                className="w-full bg-slate-800/50 border border-slate-600/50 rounded-2xl px-6 py-5 text-3xl font-black text-yellow-400 placeholder-slate-400 focus:outline-none focus:border-yellow-400/60 focus:ring-4 focus:ring-yellow-400/20 transition-all text-center"
                required
              />
            </div>
            <div>
              <label className="block text-slate-300 font-bold mb-3 text-lg">👍 Recommendation</label>
              <select
                value={formData.recommendation}
                onChange={(e) => setFormData({ ...formData, recommendation: e.target.value })}
                className="w-full bg-slate-800/50 border border-slate-600/50 rounded-2xl px-6 py-5 text-xl font-semibold text-white focus:outline-none focus:border-yellow-400/60 focus:ring-4 focus:ring-yellow-400/20 transition-all"
              >
                <option value="Yes">✅ Yes - Highly Recommend!</option>
                <option value="No">❌ No - Skip it</option>
              </select>
            </div>

            {/* Buttons - Fixed alignment */}
            <div className="lg:col-span-2 flex gap-6 pt-8 border-t border-slate-700/50">
              <button
                type="submit"
                className="flex-1 bg-gradient-to-r from-emerald-500 to-teal-600 hover:from-emerald-600 hover:to-teal-700 text-white font-black py-5 px-8 rounded-2xl shadow-2xl hover:shadow-emerald-500/50 transition-all duration-300 text-xl border border-emerald-400/50 flex items-center justify-center gap-3"
              >
                {editingId ? '💾 Update Movie' : '🎬 Add Movie'}
              </button>
              <button
                type="button"
                onClick={resetForm}
                className="flex-1 bg-gradient-to-r from-slate-700/50 to-slate-800/50 hover:from-slate-600 hover:to-slate-700 text-white font-black py-5 px-8 rounded-2xl shadow-xl hover:shadow-slate-500/25 transition-all duration-300 text-xl border border-slate-600/50 flex items-center justify-center gap-2"
              >
                ❌ Cancel
              </button>
            </div>
          </form>
        </div>
      )}

      {/* Movies Grid */}
      {loading ? (
        <div className="flex justify-center items-center h-80">
          <div className="animate-spin rounded-full h-20 w-20 border-b-2 border-yellow-500"></div>
        </div>
      ) : filteredMovies.length === 0 ? (
        <div className="text-center py-24 bg-slate-800/30 rounded-3xl p-12 border-2 border-dashed border-yellow-500/30">
          <div className="text-8xl mb-8">🎥</div>
          <h3 className="text-4xl font-bold text-slate-200 mb-4">No Movies Found</h3>
          <p className="text-xl text-slate-500 max-w-lg mx-auto">Try searching or add your first movie recommendation</p>
        </div>
      ) : (
        <div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-3 xl:grid-cols-4 gap-8">
          {filteredMovies.map((movie) => (
            <div
              key={movie.id}
              className="group bg-gradient-to-br from-slate-800/80 to-slate-900/60 backdrop-blur-xl rounded-3xl p-8 border border-slate-700/50 hover:border-yellow-400/40 hover:shadow-2xl hover:shadow-yellow-500/20 transition-all duration-500 hover:-translate-y-2 hover:scale-[1.02]"
            >
              {/* Movie Poster */}
              <div className="relative h-72 mb-6 rounded-2xl overflow-hidden bg-slate-900/50 group-hover:ring-8 group-hover:ring-yellow-400/20">
                <img
                  src={getMovieImage(movie.title, movie.poster)}
                  alt={movie.title}
                  className="w-full h-full object-cover group-hover:scale-110 transition-transform duration-700"
                  onError={(e) => {
                    e.target.src = getFallbackImage();
                  }}
                />
                {/* Genre overlay */}
                <div className={`absolute top-4 left-4 px-4 py-2 rounded-full text-xs font-bold bg-white/10 backdrop-blur-sm text-white ${genreColors[movie.genre] || 'bg-slate-900/80'}`}>
                  {movie.genre}
                </div>
                {/* Rating badge */}
                <div className={`absolute top-4 right-4 px-4 py-2 rounded-full text-sm font-bold shadow-lg ${getRatingColor(movie.rating)} bg-white/20 backdrop-blur-sm`}>
                  {'⭐'.repeat(movie.rating)}
                </div>
              </div>

              {/* Movie Info */}
              <h3 className="text-2xl font-bold text-white mb-4 line-clamp-2 group-hover:text-yellow-400 transition-colors">
                {movie.title}
              </h3>

              {/* Details */}
              <div className="space-y-3 mb-8 text-slate-400">
                <div className="flex items-center justify-between text-lg">
                  <span>Rating:</span>
                  <span className="text-2xl font-black text-yellow-400">{movie.rating}/5</span>
                </div>
                <div className="flex items-center justify-between">
                  <span>Recommend:</span>
                  <span className={`px-4 py-2 rounded-full font-bold text-sm ${movie.recommendation === 'Yes' ? 'bg-emerald-500/20 text-emerald-400 border border-emerald-400/30' : 'bg-red-500/20 text-red-400 border border-red-400/30'}`}>
                    {movie.recommendation}
                  </span>
                </div>
                {movie.poster && (
                  <div className="text-xs bg-blue-500/10 text-blue-400 px-3 py-1 rounded-full font-medium">
                    📸 Custom poster
                  </div>
                )}
              </div>

              {/* Action Buttons - Perfect alignment */}
              <div className="flex gap-4 pt-6 border-t border-slate-700/50 h-14">
                <button
                  onClick={() => handleEdit(movie)}
                  className="flex-1 h-full bg-gradient-to-r from-blue-600 to-blue-700 hover:from-blue-700 hover:to-blue-800 text-white font-bold rounded-xl shadow-lg hover:shadow-blue-500/40 transition-all duration-300 flex items-center justify-center text-sm hover:scale-[1.02]"
                >
                  ✏️ Edit
                </button>
                <button
                  onClick={() => handleDelete(movie.id)}
                  className="flex-1 h-full bg-gradient-to-r from-red-600 to-red-700 hover:from-red-700 hover:to-red-800 text-white font-bold rounded-xl shadow-lg hover:shadow-red-500/40 transition-all duration-300 flex items-center justify-center text-sm hover:scale-[1.02]"
                >
                  🗑️ Delete
                </button>
              </div>
            </div>
          ))}
        </div>
      )}
    </div>
  );
};

export default MovieManager;
